import React, { useState } from "react";
import { Link } from "react-router-dom";
import FeatureSection from "../components/FeatureSection";

const Home = () => {

  const [searchName, setSearchName] = useState("");
  const [searchLocation, setSearchLocation] = useState("");

  const events = [
    { id: 1, name: "Music Concert", location: "Chennai", date: "May 20, 2026" },
    { id: 2, name: "Tech Conference", location: "Bangalore", date: "June 5, 2026" },
    { id: 3, name: "Food Festival", location: "Hyderabad", date: "July 10, 2026" },
    { id: 4, name: "Art Exhibition", location: "Mumbai", date: "August 15, 2026" }
  ];

  const filteredEvents = events.filter(event =>
    event.name.toLowerCase().includes(searchName.toLowerCase()) &&
    event.location.toLowerCase().includes(searchLocation.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50">

      {/* HERO SECTION */}
      <section className="relative bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 text-white py-24 md:py-32 overflow-hidden">
        
        <div className="container mx-auto px-4 text-center relative z-10">
          <h1 className="text-5xl md:text-7xl font-bold mb-6">
            Welcome to EventHub! 🎉
          </h1>

          <h2 className="text-xl md:text-2xl mb-10 text-white/90 max-w-2xl mx-auto">
            Discover and book amazing events in your city.
          </h2>

          {/* SEARCH BOX */}
          <div className="bg-white/20 backdrop-blur-md border border-white/30 rounded-xl p-6 mt-8 max-w-4xl mx-auto shadow-2xl">
            <div className="flex flex-col md:flex-row gap-4 items-center">

              <input
                type="text"
                placeholder="Search Event Name"
                value={searchName}
                onChange={(e) => setSearchName(e.target.value)}
                className="flex-1 px-5 py-3 rounded-xl outline-none text-gray-800 shadow-md"
              />

              <input
                type="text"
                placeholder="Search Location"
                value={searchLocation}
                onChange={(e) => setSearchLocation(e.target.value)}
                className="flex-1 px-5 py-3 rounded-xl outline-none text-gray-800 shadow-md"
              />

              <button className="bg-white text-purple-600 font-semibold px-8 py-3 rounded-xl shadow-lg hover:bg-purple-600 hover:text-white transition duration-300">
                Search 🔍
              </button>

            </div>
          </div>
        </div>
      </section>

      {/* FILTERED EVENTS DISPLAY */}
      <section className="py-12 bg-gray-100">
        <div className="container mx-auto px-4">
          <h2 className="text-3xl font-bold mb-6 text-center">Available Events</h2>

          <div className="grid md:grid-cols-2 gap-6">
            {filteredEvents.map(event => (
              <div key={event.id} className="bg-white p-6 rounded-xl shadow-md">
                <h3 className="text-xl font-bold mb-2">{event.name}</h3>
                <p className="text-gray-600">{event.location}</p>
                <p className="text-gray-500">{event.date}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <h2 style={{
  fontSize: '2rem',
  fontWeight: 'bold',
  marginBottom: '2rem',
  textAlign: 'center'
}}>
  Popular Categories
</h2>

<div style={{
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
  gap: '30px',
  marginBottom: '60px'
}}>

  {[
    { name: 'Concerts', icon: '🎵', color: '#6366f1' },
    { name: 'Sports', icon: '⚽', color: '#22c55e' },
    { name: 'Workshops', icon: '🛠️', color: '#f59e0b' },
    { name: 'Festivals', icon: '🎉', color: '#ec4899' }
  ].map((category, index) => (

    <div
      key={index}
      style={{
        background: 'white',
        borderRadius: '20px',
        padding: '40px 20px',
        textAlign: 'center',
        boxShadow: '0 15px 35px rgba(0,0,0,0.08)',
        transition: 'all 0.4s ease',
        cursor: 'pointer'
      }}
      onMouseOver={e => {
        e.currentTarget.style.transform = 'translateY(-10px)';
        e.currentTarget.style.boxShadow = '0 20px 40px rgba(0,0,0,0.15)';
      }}
      onMouseOut={e => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 15px 35px rgba(0,0,0,0.08)';
      }}
    >
      <div style={{
        fontSize: '3rem',
        marginBottom: '20px'
      }}>
        {category.icon}
      </div>

      <h3 style={{
        fontSize: '1.4rem',
        fontWeight: '600',
        marginBottom: '15px'
      }}>
        {category.name}
      </h3>

      <button style={{
        background: category.color,
        color: 'white',
        border: 'none',
        padding: '10px 25px',
        borderRadius: '50px',
        cursor: 'pointer',
        fontWeight: '500'
      }}>
        Explore
      </button>
    </div>

  ))}

</div>

      {/* CALL TO ACTION */}
      <section className="bg-gradient-to-r from-purple-600 to-pink-600 py-20 text-center">
        <h2 className="text-4xl font-bold text-white mb-6">
          Ready to Start Your Journey?
        </h2>

        <Link
          to="/register"
          className="inline-block bg-white text-purple-600 px-10 py-4 rounded-full font-bold text-lg shadow-xl hover:scale-105 transition duration-300"
        >
          Sign Up Free 🚀
        </Link>
      </section>

    </div>
  );
};


// Category Card Component
function CategoryCard({ icon, name }) {
  return (
    <Link to="/events">
      <div className="bg-gray-100 p-8 rounded-2xl text-center hover:shadow-xl transform hover:-translate-y-2 transition duration-300 cursor-pointer">
        <div className="text-5xl mb-4">{icon}</div>
        <div className="text-lg font-semibold text-gray-800">{name}</div>
      </div>
    </Link>
  );
}

export default Home;
